import base64
import zlib
import json

# Paste your large base64 string here
data = ""
# Add missing padding if necessary
padding_needed = (4 - len(data) % 4) % 4
data += "=" * padding_needed

try:
    decoded = base64.b64decode(data)
    decompressed = zlib.decompress(decoded)
    json_data = json.loads(decompressed.decode(errors="ignore"))

    with open("data.json", "w", encoding="utf-8") as f:
        json.dump(json_data, f, indent=4)
    
    print("Successfully decompressed and saved to data.json")
except Exception as e:
    print(f"Error: {e}")